vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret=GetPixel(vUv);
vec3 orig=ret;
ret=GetPixel(vUv+ret.xz*0.1);
orig.y-=0.5;
orig=(GetPixel(vUv)+
GetPixel(vUv+0.5*orig.y)+
GetPixel(vUv+orig.y)+
GetPixel(vUv+1.5*orig.y)+
GetPixel(vUv+2*orig.y)+
GetPixel(vUv+2.5*orig.y)+
GetPixel(vUv+3*orig.y))/7;
orig.y=0;
ret.y=0;
ret=ret+orig;

  fragColor = ret;
}
